                SECLVL( +
'Cause  . . . . . :  The source member does not contain pre-compiler t-
ags and no creation command had been specified at parameter ''Creation-
 command'' (CMD).'                                                    +
                ) +
                SEV(40) +
                FMT( +
                    (*CHAR 10) +
                    (*CHAR 10) +
                    (*CHAR 10) +
                ) +
                ALROPT(*NO) +
                CCSID(65535) +
                /*  -EOF-  */

     /*-------------------------------------------------------------*/
