             ADDMSGD +
                MSGID(PRZ0031) +
                MSGF(&LIB/&OBJ) +
                MSG( +
'Invalid INCLUDE tag found in line &1.'                               +
                ) +
                SECLVL( +
'Cause  . . . . . :  Either the file or der member name is missing. Th-
e expected format is: &P >>INCLUDE<< [Library]/File Member;'          +
                ) +
                SEV(30) +
                FMT( +
                    (*DEC 6 2) +
                ) +
