             RMVMSGD MSGID(PRZ0032) MSGF(&LIB/&OBJ)
             MONMSG  MSGID(CPF2419)     /* MsgID nicht gefunden */

             ADDMSGD +
                MSGID(PRZ0032) +
                MSGF(&LIB/&OBJ) +
                MSG( +
'Nested INCLUDE tag found in line &4 of file &2/&3, member &3.'       +
                ) +
                SECLVL( +
'Cause  . . . . . :  Nested INCLUDE tags are not allowed.'            +
                ) +
                SEV(30) +
                FMT( +
                    (*CHAR 10) +
                    (*CHAR 10) +
                    (*CHAR 10) +
                    (*DEC 6 2) +
                ) +
                ALROPT(*NO) +
                CCSID(65535) +
                /*  -EOF-  */

