>>PRE-COMPILER<<              >>CMD<<
>>PRE-COMPILER<<              >>INCLUDE<<
>>PRE-COMPILER<<              >>COMPILE<<
>>PRE-COMPILER<<              >>IMPORTANT<<
>>PRE-COMPILER<<              >>CRTCMD<<
>>PRE-COMPILER<<              >>EXECUTE<<
>>PRE-COMPILER<<              >>LINK<<
>>PRE-COMPILER<<              >>WIDTH<<
>>PRE-COMPILER<<              >>CURLIB<<
